import math


def generate_input(n):
    if n <= 0:
        l = 0
        r = 0
    else:
        l = 0
        max_bits = min(n, 60)
        r = (1 << max_bits) - 1
    return f"{l} {r}"


def main():
    n = 1
    l, r = map(int, generate_input(n).split())
    for i in range(62, -1, -1):
